const fmt = v => { if (v >= 1e6) return (v/1e6).toFixed(1).replace(".",",")+"M"; if (v >= 1e3) return Math.round(v/1e3)+"K"; return v?.toLocaleString("pt-BR"); };
function useM(bp=720){const[m,setM]=useState(window.innerWidth<=bp);useEffect(()=>{const h=()=>setM(window.innerWidth<=bp);window.addEventListener("resize",h);return()=>window.removeEventListener("resize",h)},[bp]);return m}

const Tip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return <div style={{ background: "rgba(8,14,26,0.95)", border: "1px solid #C4A76C", borderRadius: 8, padding: "10px 14px", boxShadow: "0 8px 24px rgba(0,0,0,0.5)" }}>
    <div style={{ fontSize: 11, color: "#C4A76C", letterSpacing: "0.1em", marginBottom: 6, textTransform: "uppercase", fontWeight: 600 }}>{label}</div>
    {payload.map((p, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 3, fontSize: 13 }}>
      <div style={{ width: 7, height: 7, borderRadius: "50%", background: p.color, boxShadow: `0 0 5px ${p.color}` }} />
      <span style={{ color: "#C8BDA8", flex: 1, fontSize: 11 }}>{p.dataKey}</span>
      <span style={{ color: "#F5F0E4", fontWeight: 500 }}>{fmt(p.value)}</span>
    </div>)}
  </div>;
};

