function PeriodSelect({ period, setPeriod, mob, C }) {
  const [open, setOpen] = useState(false);
  useEffect(() => { if (!open) return; const h = (e) => { if (!e.target.closest("[data-period-select]")) setOpen(false); }; document.addEventListener("click", h); return () => document.removeEventListener("click", h); }, [open]);
  return <div data-period-select style={{ position: "relative", display: "inline-block", zIndex: open ? 30 : 1 }}>
    <button onClick={() => setOpen(!open)} style={{ padding: mob ? "8px 14px" : "7px 12px", fontSize: mob ? 12 : 11, borderRadius: 8, border: `1px solid ${C.dourado}`, background: C.dourado + "15", color: C.text, cursor: "pointer", letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'Marisa',serif", display: "flex", alignItems: "center", gap: 6 }}>
      {getPeriodLabel(period)}
      <ChevronDown size={10} color={C.dourado} style={{ transform: open ? "rotate(180deg)" : "none", transition: "transform 0.2s" }} />
    </button>
    {open && <div style={{ position: "absolute", bottom: "calc(100% + 6px)", left: 0, background: C.card, border: `1px solid ${C.glassBd}`, borderRadius: 10, padding: 6, zIndex: 50, minWidth: 140, maxHeight: 280, overflowY: "auto", boxShadow: "0 -8px 32px rgba(0,0,0,0.4)" }}>
      {[...allPeriods].reverse().map(pk => <button key={pk} onClick={() => { setPeriod(pk); setOpen(false); }} style={{ display: "block", width: "100%", padding: "9px 14px", fontSize: mob ? 12 : 11, color: period === pk ? C.dourado : C.sec, background: period === pk ? C.dourado + "18" : "transparent", border: "none", borderRadius: 6, cursor: "pointer", textAlign: "left", letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Marisa',serif", transition: "background 0.15s" }}>{periodLabels[pk] || pk} {period === pk && "\u2713"}</button>)}
    </div>}
  </div>;
}

function BrandPills({ brand, setBrand, mob, C }) {
  const pill = (active, color) => ({ padding: mob ? "7px 12px" : "6px 10px", fontSize: mob ? 11 : 10, borderRadius: 20, border: `1px solid ${active ? (color || C.dourado) : C.glassBd}`, background: active ? `${color || C.dourado}22` : C.glass, color: active ? C.text : C.mut, cursor: "pointer", letterSpacing: "0.05em", textTransform: "uppercase", display: "inline-flex", alignItems: "center", gap: 4, fontFamily: "'Marisa',serif" });
  return <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
    <button onClick={() => setBrand(null)} style={pill(!brand)}>Todas</button>
    {brands.map(b => <button key={b.id} onClick={() => setBrand(brand === b.id ? null : b.id)} style={pill(brand === b.id, b.color)}>
      <div style={{ width: 6, height: 6, borderRadius: "50%", background: b.color }} />{b.short}
    </button>)}
  </div>;
}

function YearSelect({ period, setPeriod, mob, C }) {
  const [open, setOpen] = useState(false);
  const years = [...new Set(allPeriods.map(pk => pk.split("-")[0]))].sort().reverse();
  const isAnual = period?.startsWith("anual-");
  const selectedYear = isAnual ? period.split("-")[1] : null;
  useEffect(() => { if (!open) return; const h = (e) => { if (!e.target.closest("[data-year-select]")) setOpen(false); }; document.addEventListener("click", h); return () => document.removeEventListener("click", h); }, [open]);
  return <div data-year-select style={{ position: "relative", display: "inline-block", zIndex: open ? 29 : 1 }}>
    <button onClick={() => setOpen(!open)} style={{ padding: mob ? "8px 14px" : "7px 12px", fontSize: mob ? 12 : 11, borderRadius: 8, border: `1px solid ${isAnual ? C.dourado : C.glassBd}`, background: isAnual ? C.dourado + "20" : C.glass, color: isAnual ? C.dourado : C.mut, cursor: "pointer", letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Marisa',serif", display: "flex", alignItems: "center", gap: 6 }}>
      {isAnual ? `Anual ${selectedYear}` : "Anual"}
      <ChevronDown size={10} color={isAnual ? C.dourado : C.mut} style={{ transform: open ? "rotate(180deg)" : "none", transition: "transform 0.2s" }} />
    </button>
    {open && <div style={{ position: "absolute", bottom: "calc(100% + 6px)", left: 0, background: C.card, border: `1px solid ${C.glassBd}`, borderRadius: 10, padding: 6, zIndex: 50, minWidth: 120, boxShadow: "0 -8px 32px rgba(0,0,0,0.4)" }}>
      {years.map(y => <button key={y} onClick={() => { setPeriod(`anual-${y}`); setOpen(false); }} style={{ display: "block", width: "100%", padding: "9px 14px", fontSize: mob ? 12 : 11, color: selectedYear === y ? C.dourado : C.sec, background: selectedYear === y ? C.dourado + "18" : "transparent", border: "none", borderRadius: 6, cursor: "pointer", textAlign: "left", letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>{y} {selectedYear === y && "\u2713"}</button>)}
    </div>}
  </div>;
}

function ChartFilters({ brand, setBrand, period, setPeriod, mob, C }) {
  return <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 10, alignItems: "center" }}>
    <PeriodSelect period={period} setPeriod={setPeriod} mob={mob} C={C} />
    <YearSelect period={period} setPeriod={setPeriod} mob={mob} C={C} />
    <div style={{ width: 1, height: 16, background: C.glassBd }} />
    <BrandPills brand={brand} setBrand={setBrand} mob={mob} C={C} />
  </div>;
}

