/* ============================================================
   VISÃO DO SÓCIO — Redesign DashCortex
============================================================ */
function SocioView({ onSwitch, C, mode, toggle }) {
  const mob = useM();
  useEffect(() => { const s = document.createElement("style"); s.textContent = FONT_CSS; document.head.appendChild(s); return () => s.remove(); }, []);
  const [tab, setTab] = useState("monte-dourado");
  const [brand, setBrand] = useState(null);
  const [period, setPeriod] = useState(allPeriods[allPeriods.length - 1]);
  const [menu, setMenu] = useState(false);
  const [ready, setReady] = useState(false);
  useEffect(() => { setTimeout(() => setReady(true), 80); }, []);
  const fi = d => ({ opacity: ready ? 1 : 0, transform: ready ? "translateY(0)" : "translateY(8px)", transition: `all 0.5s cubic-bezier(.4,0,.2,1) ${d}ms` });

  const empBrands = brands.filter(b => b.id !== "monte-dourado");
  const activeBrand = tab === "monte-dourado" ? "monte-dourado" : brand;

  // Dropdown state for period
  const [pOpen, setPOpen] = useState(false);
  const [yOpen, setYOpen] = useState(false);
  useEffect(() => { if (!pOpen) return; const h = e => { if (!e.target.closest("[data-psel]")) setPOpen(false); }; document.addEventListener("click", h); return () => document.removeEventListener("click", h); }, [pOpen]);
  useEffect(() => { if (!yOpen) return; const h = e => { if (!e.target.closest("[data-ysel]")) setYOpen(false); }; document.addEventListener("click", h); return () => document.removeEventListener("click", h); }, [yOpen]);
  const years = [...new Set(allPeriods.map(pk => pk.split("-")[0]))].sort().reverse();
  const isAnual = period?.startsWith("anual-");

  const currentKpis = isAnual
    ? (activeBrand ? getAnualKpis(activeBrand, period.split("-")[1]) : getGeralAnualKpis(period.split("-")[1]))
    : (activeBrand ? getKpis(activeBrand, period) : getGeralKpis(period));

  // === SIDEBAR WIDTH ===
  const SW = mob ? 0 : 68;

  // === CARD STYLE ===
  const card = { background: C.card, border: `1px solid ${C.glassBd}`, borderRadius: 10 };

  // === SIDEBAR ICONS ===
  const SideIcon = ({ active, label, children, onClick }) => (
    <button onClick={onClick} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5, padding: "10px 4px", borderRadius: 8, background: active ? C.dourado + "12" : "transparent", border: active ? `1px solid ${C.dourado}25` : "1px solid transparent", cursor: "pointer", width: "100%", transition: "all 0.2s" }}>
      <div style={{ width: 32, height: 32, borderRadius: 8, background: active ? C.dourado + "20" : "rgba(255,255,255,0.04)", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.2s" }}>{children}</div>
      <span style={{ fontSize: 7.5, color: active ? C.dourado : C.mut, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif", textAlign: "center", lineHeight: 1.1, maxWidth: 56 }}>{label}</span>
    </button>
  );

  // === KPI CARD with progress bar ===
  const KpiCard = ({ k, delay }) => {
    if (!k) return null;
    const pctVal = Math.min(Math.abs(parseFloat(k.p)) || 0, 100);
    const barColor = k.u ? "#22c55e" : "#ef4444";
    return (
      <div style={{ ...card, padding: mob ? "14px 12px" : "16px 14px", ...fi(delay) }}>
        <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Gotham',sans-serif" }}>{k.k}</div>
        <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: k.p ? 10 : 0 }}>
          <span style={{ fontSize: mob ? 22 : 26, fontWeight: 500, lineHeight: 1, fontFamily: "'Marisa',serif", color: C.text }}>{k.v}</span>
          {k.p && <span style={{ fontSize: 11, color: barColor, fontWeight: 600, fontFamily: "'Gotham',sans-serif" }}>{k.noArrow ? "" : (k.u ? "\u25B2" : "\u25BC")} {k.p}</span>}
        </div>
        {k.p && !k.noArrow && pctVal > 0 && (
          <div style={{ width: "100%", height: 5, borderRadius: 3, background: "rgba(255,255,255,0.04)", overflow: "hidden" }}>
            <div style={{ height: "100%", borderRadius: 3, width: `${pctVal}%`, background: `linear-gradient(90deg, ${barColor}, ${barColor}aa)`, transition: "width 1s ease" }} />
          </div>
        )}
      </div>
    );
  };

  // === CHART SECTION ===
  const ChartSection = ({ title, suffix, id }) => {
    const visBrands = tab === "monte-dourado" ? [brands[0]] : (brand ? empBrands.filter(b => b.id === brand) : empBrands);
    const data = chartData.map(r => { const row = { m: r.m }; visBrands.forEach(b => { row[b.name] = r[`${b.name}${suffix}`] || 0; }); return row; });
    return (
      <div style={{ ...card, padding: mob ? "14px 10px 8px" : "16px 14px 10px" }}>
        <div style={{ fontSize: 10, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 10, fontFamily: "'Gotham',sans-serif" }}>{title}</div>
        <ResponsiveContainer width="100%" height={mob ? 180 : 200}>
          <AreaChart data={data}>
            <defs>{visBrands.map(b => <linearGradient key={`${id}${b.id}`} id={`${id}${b.id}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={b.color} stopOpacity={0.25} /><stop offset="100%" stopColor={b.color} stopOpacity={0} /></linearGradient>)}</defs>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.10)" vertical={false} />
            <XAxis dataKey="m" tick={{ fill: C.mut, fontSize: 10 }} axisLine={false} tickLine={false} />
            <YAxis tick={{ fill: C.mut, fontSize: 9 }} axisLine={false} tickLine={false} tickFormatter={fmt} width={42} />
            <Tooltip content={<Tip />} />
            {visBrands.map(b => <Area key={b.id} type="monotone" dataKey={b.name} stroke={b.color} strokeWidth={2} fill={`url(#${id}${b.id})`} dot={false} activeDot={{ r: 4, fill: b.color, stroke: C.bg, strokeWidth: 2 }} />)}
          </AreaChart>
        </ResponsiveContainer>
        {visBrands.length > 1 && <div style={{ display: "flex", gap: 12, marginTop: 6, paddingLeft: 4 }}>
          {visBrands.map(b => <div key={b.id} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 9, color: C.sec }}><div style={{ width: 8, height: 3, borderRadius: 1, background: b.color }} />{b.short}</div>)}
        </div>}
      </div>
    );
  };

  // ============================
  // RENDER
  // ============================
  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.text, fontFamily: "'Gotham','Inter',-apple-system,sans-serif", display: "flex" }}>

      {/* ===== SIDEBAR (desktop) ===== */}
      {!mob && (
        <aside style={{ width: SW, position: "fixed", top: 0, left: 0, bottom: 0, background: C.sidebar || C.card, borderRight: `1px solid ${C.glassBd}`, display: "flex", flexDirection: "column", alignItems: "center", padding: "16px 4px 12px", zIndex: 50, gap: 4 }}>
          <div style={{ marginBottom: 14 }}><Logo lc={C.dourado} w={48} /></div>
          <SideIcon active={tab === "monte-dourado"} label="Monte Dourado" onClick={() => { setTab("monte-dourado"); setBrand(null); }}>
           <MdSymbol color={tab === "monte-dourado" ? C.dourado : C.mut} size={32} />
          </SideIcon>
          <SideIcon active={tab === "empreendimentos"} label="Empreend." onClick={() => { setTab("empreendimentos"); setBrand(null); }}>
            <Building2 size={16} color={tab === "empreendimentos" ? C.dourado : C.mut} strokeWidth={1.5} />
          </SideIcon>
          <SideIcon active={tab === "eventos"} label="Eventos" onClick={() => { setTab("eventos"); setBrand(null); }}>
            <CalendarDays size={16} color={tab === "eventos" ? C.dourado : C.mut} strokeWidth={1.5} />
          </SideIcon>
          <div style={{ flex: 1 }} />
          <button onClick={toggle} style={{ background: "none", border: "none", cursor: "pointer", padding: 8, borderRadius: 6, opacity: 0.5 }} title={mode === "dark" ? "Modo claro" : "Modo escuro"}>
            {mode === "dark" ? <Sun size={15} color={C.sec} strokeWidth={1.5} /> : <Moon size={15} color={C.sec} strokeWidth={1.5} />}
          </button>
          <button onClick={onSwitch} style={{ background: "none", border: "none", cursor: "pointer", padding: 8, borderRadius: 6, opacity: 0.5 }} title="Admin">
            <Lock size={15} color={C.sec} strokeWidth={1.5} />
          </button>
        </aside>
      )}

      {/* ===== CONTENT AREA ===== */}
      <div style={{ flex: 1, marginLeft: mob ? 0 : SW, minHeight: "100vh", display: "flex", flexDirection: "column" }}>

        {/* TOP BAR */}
        <header style={{ position: "sticky", top: 0, zIndex: 40, background: C.topbar, backdropFilter: "blur(20px)", borderBottom: `1px solid ${C.glassBd}`, padding: mob ? "8px 12px" : "8px 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            {mob && <Logo lc={C.text} w={110} />}
            {!mob && <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <MdSymbol color={C.dourado} size={36} />
              <span style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>
                {tab === "monte-dourado" ? "Monte Dourado" : tab === "empreendimentos" ? "Empreendimentos" : "Eventos"}
              </span>
              <span style={{ fontSize: 9, color: C.mut, padding: "3px 8px", background: "rgba(255,255,255,0.04)", borderRadius: 4, fontFamily: "'Gotham',sans-serif" }}>{getPeriodLabel(period)}</span>
            </div>}
          </div>
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            {mob && <button onClick={toggle} style={{ background: "rgba(255,255,255,0.04)", border: `1px solid ${C.glassBd}`, borderRadius: 6, padding: "6px 8px", cursor: "pointer", color: C.sec, display: "flex", alignItems: "center" }}>{mode === "dark" ? <Sun size={14} color={C.dourado} /> : <Moon size={14} color={C.dourado} />}</button>}
            {mob && <button onClick={onSwitch} style={{ background: "rgba(255,255,255,0.04)", border: `1px solid ${C.glassBd}`, borderRadius: 6, padding: "6px 10px", cursor: "pointer", fontSize: 9, color: C.dourado, letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif" }}>Admin</button>}
            <button onClick={() => setMenu(!menu)} style={{ background: "rgba(255,255,255,0.04)", border: `1px solid ${C.glassBd}`, borderRadius: 6, padding: "6px 10px", cursor: "pointer", color: C.sec, display: "flex", alignItems: "center", gap: 5, fontSize: 10 }}>
              <Menu size={14} color={C.sec} strokeWidth={1.5} />
              {!mob && "Filtros"}
            </button>
          </div>
        </header>

        {/* MOBILE TABS */}
        {mob && <div style={{ display: "flex", borderBottom: `1px solid ${C.glassBd}`, background: C.bg }}>
          {[["monte-dourado","Monte Dourado"],["empreendimentos","Empreend."],["eventos","Eventos"]].map(([id,lbl]) => (
            <button key={id} onClick={() => { setTab(id); setBrand(null); }} style={{ flex: 1, padding: "10px 0", fontSize: 10, letterSpacing: "0.06em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif", background: "none", border: "none", borderBottom: `2px solid ${tab === id ? C.dourado : "transparent"}`, color: tab === id ? C.dourado : C.mut, cursor: "pointer", transition: "all 0.2s" }}>{lbl}</button>
          ))}
        </div>}

        {/* FILTER PANEL (slide-over) */}
        {menu && <div onClick={() => setMenu(false)} style={{ position: "fixed", inset: 0, zIndex: 39, background: "rgba(0,0,0,0.6)" }} />}
        <div style={{ position: "fixed", top: 0, right: 0, bottom: 0, width: mob ? "80%" : "280px", zIndex: 40, background: C.card, borderLeft: `1px solid ${C.glassBd}`, padding: "16px 14px", overflowY: "auto", transform: menu ? "translateX(0)" : "translateX(100%)", transition: "transform 0.25s ease" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <span style={{ fontSize: 11, color: C.dourado, letterSpacing: "0.1em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif" }}>Filtros</span>
            <button onClick={() => setMenu(false)} style={{ color: C.mut, fontSize: 18, cursor: "pointer", background: "none", border: "none", lineHeight: 1 }}>&times;</button>
          </div>
          {tab === "empreendimentos" && <>
            <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6, fontFamily: "'Gotham',sans-serif" }}>Empreendimento</div>
            {[{ id: null, name: "Todos", color: C.dourado }, ...empBrands].map(b => (
              <button key={b.id||"all"} onClick={() => { setBrand(b.id); setMenu(false); }} style={{ width: "100%", padding: "10px 12px", marginBottom: 4, borderRadius: 6, background: (brand === b.id || (!brand && !b.id)) ? "rgba(255,255,255,0.04)" : "transparent", color: (brand === b.id || (!brand && !b.id)) ? C.text : C.sec, border: `1px solid ${(brand === b.id || (!brand && !b.id)) ? (b.color || C.dourado) + "40" : "transparent"}`, cursor: "pointer", textAlign: "left", fontSize: 11, letterSpacing: "0.04em", display: "flex", alignItems: "center", gap: 8, fontFamily: "'Gotham',sans-serif" }}>
                {b.color && b.id && <div style={{ width: 8, height: 8, borderRadius: "50%", background: b.color }} />}
                {b.name}
                {b.tag && <span style={{ fontSize: 7, color: C.mut, marginLeft: "auto" }}>{b.tag}</span>}
              </button>
            ))}
            <div style={{ height: 1, background: C.glassBd, margin: "10px 0" }} />
          </>}
          <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6, fontFamily: "'Gotham',sans-serif" }}>Anual</div>
          {years.map(y => <button key={y} onClick={() => { setPeriod(`anual-${y}`); setMenu(false); }} style={{ width: "100%", padding: "8px 12px", marginBottom: 3, borderRadius: 6, background: period === `anual-${y}` ? C.dourado + "15" : "transparent", color: period === `anual-${y}` ? C.dourado : C.sec, border: "none", cursor: "pointer", textAlign: "left", fontSize: 11, fontFamily: "'Gotham',sans-serif" }}>{y} {period === `anual-${y}` && "\u2713"}</button>)}
          <div style={{ height: 1, background: C.glassBd, margin: "10px 0" }} />
          <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6, fontFamily: "'Gotham',sans-serif" }}>Mensal</div>
          {[...allPeriods].reverse().map(pk => <button key={pk} onClick={() => { setPeriod(pk); setMenu(false); }} style={{ width: "100%", padding: "8px 12px", marginBottom: 2, borderRadius: 6, background: period === pk ? C.dourado + "15" : "transparent", color: period === pk ? C.dourado : C.sec, border: "none", cursor: "pointer", textAlign: "left", fontSize: 11, fontFamily: "'Gotham',sans-serif" }}>{periodLabels[pk] || pk} {period === pk && "\u2713"}</button>)}
        </div>

        {/* ===== MAIN CONTENT ===== */}
        <main style={{ flex: 1, padding: mob ? "14px 10px" : "18px 22px", maxWidth: 1360, width: "100%", margin: "0 auto" }}>

          {/* === ABA EVENTOS === */}
          {tab === "eventos" && <div style={{ ...fi(0) }}>
            <div style={{ ...card, padding: mob ? "40px 20px" : "60px 40px", textAlign: "center", marginTop: 10 }}>
              <CalendarDays size={40} color={C.dourado} strokeWidth={1} style={{ marginBottom: 16, opacity: 0.6 }} />
              <h3 style={{ fontSize: 18, fontWeight: 400, marginBottom: 8, fontFamily: "'Marisa',serif", textTransform: "uppercase", letterSpacing: "0.06em", color: C.text }}>Em breve</h3>
              <p style={{ fontSize: 12, color: C.sec, lineHeight: 1.7, maxWidth: 400, margin: "0 auto 16px", fontFamily: "'Gotham',sans-serif" }}>Campeonatos de surf, ações na Taíba, encontros com corretores e lançamentos.</p>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap", justifyContent: "center" }}>
                {["QS Taíba Pro","Surf na Laje","Open House","Lançamentos"].map(e => <span key={e} style={{ fontSize: 9, color: C.mut, background: "rgba(255,255,255,0.03)", border: `1px solid ${C.glassBd}`, padding: "4px 10px", borderRadius: 12, fontFamily: "'Gotham',sans-serif" }}>{e}</span>)}
              </div>
            </div>
          </div>}

          {/* === ABAS MONTE DOURADO / EMPREENDIMENTOS === */}
          {tab !== "eventos" && <>

            {/* PERIOD FILTERS */}
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center", marginBottom: mob ? 14 : 16, ...fi(0) }}>
              <div data-psel style={{ position: "relative", zIndex: pOpen ? 20 : 1 }}>
                <button onClick={() => setPOpen(!pOpen)} style={{ padding: "6px 12px", fontSize: 10, borderRadius: 6, border: `1px solid ${C.glassBd}`, background: "rgba(255,255,255,0.03)", color: C.text, cursor: "pointer", letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif", display: "flex", alignItems: "center", gap: 5 }}>
                  {getPeriodLabel(period)}
                  <ChevronDown size={10} color={C.mut} style={{ transform: pOpen ? "rotate(180deg)" : "none", transition: "0.2s" }} />
                </button>
                {pOpen && <div style={{ position: "absolute", bottom: "calc(100% + 4px)", left: 0, background: C.card, border: `1px solid ${C.glassBd}`, borderRadius: 8, padding: 4, minWidth: 130, maxHeight: 260, overflowY: "auto", boxShadow: "0 -4px 24px rgba(0,0,0,0.5)", zIndex: 30 }}>
                  {[...allPeriods].reverse().map(pk => <button key={pk} onClick={() => { setPeriod(pk); setPOpen(false); }} style={{ display: "block", width: "100%", padding: "7px 10px", fontSize: 10, color: period === pk ? C.dourado : C.sec, background: period === pk ? C.dourado + "12" : "transparent", border: "none", borderRadius: 4, cursor: "pointer", textAlign: "left", fontFamily: "'Gotham',sans-serif" }}>{periodLabels[pk]} {period === pk && "\u2713"}</button>)}
                </div>}
              </div>
              <div data-ysel style={{ position: "relative", zIndex: yOpen ? 20 : 1 }}>
                <button onClick={() => setYOpen(!yOpen)} style={{ padding: "6px 12px", fontSize: 10, borderRadius: 6, border: `1px solid ${isAnual ? C.dourado + "40" : C.glassBd}`, background: isAnual ? C.dourado + "10" : "rgba(255,255,255,0.03)", color: isAnual ? C.dourado : C.mut, cursor: "pointer", letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif", display: "flex", alignItems: "center", gap: 5 }}>
                  {isAnual ? `Anual ${period.split("-")[1]}` : "Anual"}
                  <ChevronDown size={10} color={isAnual ? C.dourado : C.mut} style={{ transform: yOpen ? "rotate(180deg)" : "none", transition: "0.2s" }} />
                </button>
                {yOpen && <div style={{ position: "absolute", bottom: "calc(100% + 4px)", left: 0, background: C.card, border: `1px solid ${C.glassBd}`, borderRadius: 8, padding: 4, minWidth: 100, boxShadow: "0 -4px 24px rgba(0,0,0,0.5)", zIndex: 30 }}>
                  {years.map(y => <button key={y} onClick={() => { setPeriod(`anual-${y}`); setYOpen(false); }} style={{ display: "block", width: "100%", padding: "7px 10px", fontSize: 10, color: period === `anual-${y}` ? C.dourado : C.sec, background: period === `anual-${y}` ? C.dourado + "12" : "transparent", border: "none", borderRadius: 4, cursor: "pointer", textAlign: "left", fontFamily: "'Gotham',sans-serif" }}>{y} {period === `anual-${y}` && "\u2713"}</button>)}
                </div>}
              </div>
            </div>

            {/* ============================================
                ABA MONTE DOURADO — separado por canal
            ============================================= */}
            {tab === "monte-dourado" && <>
              {/* SEÇÃO: INSTAGRAM */}
              <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(50) }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, padding: mob ? "12px 14px" : "14px 16px", borderBottom: `1px solid ${C.glassBd}`, borderLeft: `3px solid #E1306C` }}>
                  <Instagram size={18} color="#E1306C" strokeWidth={1.5} />
                  <div>
                    <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>Instagram</div>
                    <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>@monte.dourado · {getPeriodLabel(period)}</div>
                  </div>
                </div>
                <div style={{ padding: mob ? "12px 10px" : "14px 14px" }}>
                  <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr 1fr" : "repeat(4,1fr)", gap: 6, marginBottom: 14 }}>
                    {(currentKpis || []).map((k, i) => <KpiCard key={k?.k || i} k={k} delay={80 + i * 50} />)}
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr" : "1fr 1fr", gap: 8 }}>
                    <ChartSection title="Alcance" suffix="_alc" id="md_alc" />
                    <ChartSection title="Visualizações" suffix="_views" id="md_vw" />
                  </div>
                </div>
              </div>

              {/* SEÇÃO: TIKTOK */}
              <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(200) }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, padding: mob ? "12px 14px" : "14px 16px", borderLeft: `3px solid #69C9D0`, opacity: 0.5 }}>
                  <Music2 size={18} color="#69C9D0" strokeWidth={1.5} />
                  <div>
                    <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>TikTok</div>
                    <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>Em breve</div>
                  </div>
                </div>
              </div>

              {/* SEÇÃO: YOUTUBE */}
              <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(250) }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, padding: mob ? "12px 14px" : "14px 16px", borderLeft: `3px solid #FF0000`, opacity: 0.5 }}>
                  <Youtube size={18} color="#FF0000" strokeWidth={1.5} />
                  <div>
                    <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>YouTube</div>
                    <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>Em breve</div>
                  </div>
                </div>
              </div>
            </>}

            {/* ============================================
                ABA EMPREENDIMENTOS — separado por empresa
            ============================================= */}
            {tab === "empreendimentos" && <>

              {/* SEÇÃO: VILA DO CHAPÉU */}
              {(!brand || brand === "vila-chapeu") && (
                <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(50) }}>
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: mob ? "12px 14px" : "14px 16px", borderBottom: `1px solid ${C.glassBd}`, borderLeft: "3px solid #7A9BBF" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                      <div style={{ width: 32, height: 32, borderRadius: 8, background: "#7A9BBF18", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <Home size={16} color="#7A9BBF" strokeWidth={1.5} />
                      </div>
                      <div>
                        <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>Vila do Chapéu</div>
                        <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>@viladochapeutaiba · {getPeriodLabel(period)}</div>
                      </div>
                    </div>
                    <span style={{ fontSize: 8, color: "#7A9BBF", background: "#7A9BBF12", padding: "3px 8px", borderRadius: 4, border: "1px solid #7A9BBF25", fontFamily: "'Gotham',sans-serif" }}>100% orgânico · vendido</span>
                  </div>
                  <div style={{ padding: mob ? "12px 10px" : "14px 14px" }}>
                    <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr 1fr" : "repeat(4,1fr)", gap: 6, marginBottom: 14 }}>
                      {(getKpis("vila-chapeu", period) || []).map((k, i) => <KpiCard key={k?.k || i} k={k} delay={80 + i * 50} />)}
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr" : "1fr 1fr", gap: 8 }}>
                      {(() => { const visBrands = [brands.find(b=>b.id==="vila-chapeu")].filter(Boolean); const data = chartData.map(r => ({ m: r.m, [visBrands[0]?.name]: r[`${visBrands[0]?.name}_alc`] || 0 }));
                        return <div style={{ ...card, padding: "12px 10px 6px" }}>
                          <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Gotham',sans-serif" }}>Alcance</div>
                          <ResponsiveContainer width="100%" height={150}><AreaChart data={data}><defs><linearGradient id="vc_a" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#7A9BBF" stopOpacity={0.25}/><stop offset="100%" stopColor="#7A9BBF" stopOpacity={0}/></linearGradient></defs><CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.10)" vertical={false}/><XAxis dataKey="m" tick={{ fill: C.mut, fontSize: 9 }} axisLine={false} tickLine={false}/><YAxis tick={{ fill: C.mut, fontSize: 8 }} axisLine={false} tickLine={false} tickFormatter={fmt} width={36}/><Tooltip content={<Tip/>}/><Area type="monotone" dataKey={visBrands[0]?.name} stroke="#7A9BBF" strokeWidth={2} fill="url(#vc_a)" dot={false} activeDot={{ r: 3, fill: "#7A9BBF" }}/></AreaChart></ResponsiveContainer>
                        </div>;
                      })()}
                      {(() => { const visBrands = [brands.find(b=>b.id==="vila-chapeu")].filter(Boolean); const data = chartData.map(r => ({ m: r.m, [visBrands[0]?.name]: r[`${visBrands[0]?.name}_views`] || 0 }));
                        return <div style={{ ...card, padding: "12px 10px 6px" }}>
                          <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Gotham',sans-serif" }}>Visualizações</div>
                          <ResponsiveContainer width="100%" height={150}><AreaChart data={data}><defs><linearGradient id="vc_v" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#7A9BBF" stopOpacity={0.25}/><stop offset="100%" stopColor="#7A9BBF" stopOpacity={0}/></linearGradient></defs><CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.10)" vertical={false}/><XAxis dataKey="m" tick={{ fill: C.mut, fontSize: 9 }} axisLine={false} tickLine={false}/><YAxis tick={{ fill: C.mut, fontSize: 8 }} axisLine={false} tickLine={false} tickFormatter={fmt} width={36}/><Tooltip content={<Tip/>}/><Area type="monotone" dataKey={visBrands[0]?.name} stroke="#7A9BBF" strokeWidth={2} fill="url(#vc_v)" dot={false} activeDot={{ r: 3, fill: "#7A9BBF" }}/></AreaChart></ResponsiveContainer>
                        </div>;
                      })()}
                    </div>
                  </div>
                </div>
              )}

              {/* SEÇÃO: VILA DO MORRO */}
              {(!brand || brand === "vila-morro") && (
                <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(150) }}>
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: mob ? "12px 14px" : "14px 16px", borderBottom: `1px solid ${C.glassBd}`, borderLeft: "3px solid #6B8F7B" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                      <div style={{ width: 32, height: 32, borderRadius: 8, background: "#6B8F7B18", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <TreePine size={16} color="#6B8F7B" strokeWidth={1.5} />
                      </div>
                      <div>
                        <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>Vila do Morro</div>
                        <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>ADS · Meta Ads + Google Ads · {getPeriodLabel(period)}</div>
                      </div>
                    </div>
                    <span style={{ fontSize: 8, color: "#6B8F7B", background: "#6B8F7B12", padding: "3px 8px", borderRadius: 4, border: "1px solid #6B8F7B25", fontFamily: "'Gotham',sans-serif" }}>@monte.dourado</span>
                  </div>
                  <div style={{ padding: mob ? "12px 10px" : "14px 14px" }}>
                    <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr 1fr" : "repeat(4,1fr)", gap: 6, marginBottom: 14 }}>
                      {(getKpis("vila-morro", period) || []).map((k, i) => <KpiCard key={k?.k || i} k={k} delay={180 + i * 50} />)}
                    </div>
                    <div style={{ ...card, padding: "12px 10px 6px" }}>
                      <div style={{ fontSize: 9, color: C.mut, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Gotham',sans-serif" }}>Investimento mensal</div>
                      <ResponsiveContainer width="100%" height={160}>
                        <BarChart data={invHistory} barSize={mob ? 28 : 40}>
                          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.10)" vertical={false} />
                          <XAxis dataKey="m" tick={{ fill: C.mut, fontSize: 9 }} axisLine={false} tickLine={false} />
                          <YAxis tick={{ fill: C.mut, fontSize: 8 }} axisLine={false} tickLine={false} tickFormatter={v => `R$${fmt(v)}`} width={50} />
                          <Tooltip content={({ active, payload }) => active && payload?.length ? <div style={{ background: "rgba(8,14,26,0.95)", border: "1px solid #6B8F7B", borderRadius: 6, padding: "8px 12px", boxShadow: "0 4px 16px rgba(0,0,0,0.5)" }}><div style={{ fontSize: 10, color: "#6B8F7B", textTransform: "uppercase", marginBottom: 4 }}>{payload[0]?.payload?.m}</div><div style={{ fontSize: 13, color: "#F5F0E4", fontWeight: 500 }}>R$ {payload[0].value?.toLocaleString("pt-BR")}</div><div style={{ fontSize: 9, color: "#C8BDA8", marginTop: 2 }}>Meta {payload[0]?.payload?.meta?.toLocaleString("pt-BR")} · Google {payload[0]?.payload?.google?.toLocaleString("pt-BR")}</div></div> : null} />
                          <Bar dataKey="Vila do Morro" radius={[4, 4, 0, 0]} fill="#6B8F7B" />
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                </div>
              )}

              {/* SEÇÃO: VILA DA ILHA */}
              <div style={{ ...card, marginBottom: 10, overflow: "hidden", ...fi(250) }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, padding: mob ? "12px 14px" : "14px 16px", borderLeft: "3px solid #B07D8A", opacity: 0.5 }}>
                  <div style={{ width: 32, height: 32, borderRadius: 8, background: "#B07D8A18", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <Globe size={16} color="#B07D8A" strokeWidth={1.5} />
                  </div>
                  <div>
                    <div style={{ fontSize: 12, fontWeight: 500, color: C.text, letterSpacing: "0.04em", textTransform: "uppercase", fontFamily: "'Marisa',serif" }}>Vila da Ilha</div>
                    <div style={{ fontSize: 9, color: C.mut, fontFamily: "'Gotham',sans-serif" }}>Marca em criação · sem dados</div>
                  </div>
                </div>
              </div>
            </>}

            {/* LEITURA AUTOMÁTICA */}
            {(() => {
              const insights = {
                "monte-dourado": { title: "Março consolidou conteúdo como motor de crescimento.", body: ["Interações explodiram +387% impulsionadas pelos campeonatos QS e Surf na Laje. Alcance orgânico cresceu 50%.", "Base chegou a 15.031 seguidores (+610). Visualizações saltaram 76% para mais de 1 milhão."], tag: "Mar 2026" },
                "vila-chapeu": { title: "Vila do Chapéu opera no piloto automático.", body: ["Empreendimento vendido, perfil 100% orgânico, 707 seguidores.", "Cadência mínima preserva a base."], tag: "Abr 2026" },
                "vila-morro": { title: "Vila do Morro investiu R$ 40,3 mil em 3 meses.", body: ["1.354 mensagens via Meta Ads. Anúncios rodam no perfil @monte.dourado."], tag: "ADS" },
                "geral": { title: "3 marcas, 3 momentos diferentes.", body: ["Monte Dourado lidera. Vila do Chapéu opera orgânico. Vila do Morro investe em ADS."], tag: "Geral" },
              };
              const ins = tab === "monte-dourado" ? insights["monte-dourado"] : (insights[brand] || insights["geral"]);
              return (
                <div style={{ ...card, padding: mob ? "14px 12px" : "16px 16px", position: "relative", overflow: "hidden", background: C.insightBg, ...fi(300) }}>
                  <div style={{ position: "absolute", top: -20, right: -20, width: 120, height: 120, background: `radial-gradient(circle,${C.dourado}15,transparent 70%)`, pointerEvents: "none" }} />
                  <div style={{ position: "relative", zIndex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 5, marginBottom: 8 }}>
                      <div style={{ width: 4, height: 4, borderRadius: "50%", background: C.dourado }} />
                      <span style={{ fontSize: 8, color: C.dourado, letterSpacing: "0.1em", textTransform: "uppercase", fontFamily: "'Gotham',sans-serif" }}>Leitura automática</span>
                    </div>
                    <h3 style={{ fontSize: 14, fontWeight: 400, lineHeight: 1.4, marginBottom: 6, fontFamily: "'Marisa',serif" }}>{ins.title}</h3>
                    {ins.body.map((p, i) => <p key={i} style={{ fontSize: 11, color: C.sec, lineHeight: 1.6, marginBottom: 4, fontFamily: "'Gotham',sans-serif" }}>{p}</p>)}
                  </div>
                </div>
              );
            })()}
          </>}
        </main>

        {/* FOOTER */}
        <footer style={{ borderTop: `1px solid ${C.glassBd}`, padding: mob ? "16px 12px" : "18px 22px", marginTop: "auto" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
            <Logo lc={C.mut} w={mob ? 70 : 90} />
            <p style={{ fontSize: mob ? 8 : 9, color: C.mut, fontFamily: "'Gotham',sans-serif", textAlign: "center", flex: 1 }}>Painel de desempenho digital · Monte Dourado Incorporações</p>
            <div style={{ fontSize: mob ? 7 : 8, color: C.douDim, fontFamily: "'Gotham',sans-serif", letterSpacing: "0.03em", whiteSpace: "nowrap" }}>Powered by <span style={{ color: C.dourado }}>Vitória Rocha</span></div>
          </div>
        </footer>
      </div>{/* end content area */}
    </div>
  );
}
/* ============================================================
   VISÃO DA VITÓRIA (ADMIN)
============================================================ */
function AdminView({ onSwitch, C, mode, toggle }) {
  const mob = useM();
  useEffect(() => { if (!document.querySelector("[data-md-fonts]")) { const s = document.createElement("style"); s.textContent = FONT_CSS; s.dataset.mdFonts = "1"; document.head.appendChild(s); } }, []);
  const [step, setStep] = useState("login"); // login | select | upload | extracting | review | done
  const [brandId, setBrandId] = useState("monte-dourado");
  const [periodKey, setPeriodKey] = useState("2026-03");
  const [pdfName, setPdfName] = useState("");
  const [docxName, setDocxName] = useState("");
  const [progress, setProgress] = useState(0);
  const [editData, setEditData] = useState(null);

  const simulateExtraction = () => {
    setStep("extracting");
    setProgress(0);
    const steps = ["Enviando PDF...", "Lendo páginas...", "Identificando métricas...", "Gerando insights...", "Finalizando..."];
    let i = 0;
    const iv = setInterval(() => {
      i++;
      setProgress(Math.min(i * 20, 100));
      if (i >= 5) {
        clearInterval(iv);
        setTimeout(() => {
          setEditData({ ...extractedMock });
          setStep("review");
        }, 400);
      }
    }, 600);
  };

  const simulatePublish = () => {
    setStep("extracting");
    setProgress(0);
    setTimeout(() => setProgress(50), 300);
    setTimeout(() => setProgress(100), 600);
    setTimeout(() => setStep("done"), 1000);
  };

  const sty = {
    label: { fontSize: 10, color: C.douDim, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Marisa',serif", display: "block" },
    input: { width: "100%", padding: "12px 14px", background: C.bg, border: `1px solid ${C.border}`, borderRadius: 8, color: C.text, fontSize: 14, outline: "none" },
    select: { width: "100%", padding: "12px 14px", background: C.bg, border: `1px solid ${C.border}`, borderRadius: 8, color: C.text, fontSize: 14, outline: "none" },
    btn: { padding: "13px 24px", background: C.dourado, color: C.bg, borderRadius: 8, fontSize: 12, fontWeight: 600, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer", border: "none" },
    btnOut: { padding: "13px 24px", background: "transparent", color: C.sec, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer" },
  };

  return <div style={{ minHeight: "100vh", background: C.bg, color: C.text, fontFamily: "'Gotham','Inter',-apple-system,sans-serif" }}>
    <header style={{ background: C.bg + "ee", borderBottom: `1px solid ${C.glassBd}`, padding: mob ? "10px 14px" : "12px 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <span style={{ fontSize: 10, color: C.dourado, letterSpacing: "0.12em", textTransform: "uppercase", padding: "4px 8px", fontFamily: "'Marisa',serif", border: `1px solid ${C.dourado}33`, borderRadius: 4 }}>Admin</span>
        <Logo lc={C.text} w={mob ? 140 : 160} />
      </div>
      <div style={{ display: "flex", gap: 8 }}>
        <button onClick={toggle} style={{ ...gl(C), padding: "8px 12px", cursor: "pointer", fontSize: 11, color: C.sec, display: "flex", alignItems: "center", gap: 5 }}>{mode === "dark" ? <Sun size={13} color={C.dourado} strokeWidth={1.5} /> : <Moon size={13} color={C.dourado} strokeWidth={1.5} />}{mob ? "" : (mode === "dark" ? "Claro" : "Escuro")}</button>
        <button onClick={onSwitch} style={{ ...gl(C), padding: "8px 14px", cursor: "pointer", fontSize: 11, color: C.sec, letterSpacing: "0.08em", textTransform: "uppercase" }}>Ver painel</button>
      </div>
    </header>

    <main style={{ maxWidth: 720, margin: "0 auto", padding: mob ? "24px 14px" : "32px 20px" }}>

      {/* LOGIN */}
      {step === "login" && (
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: "60vh" }}>
          <div style={{ ...gls(C), padding: 32, width: 360, textAlign: "center" }}>
            <div style={{ fontSize: 10, color: C.dourado, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 8 }}>Painel administrativo</div>
            <div style={{ marginBottom: 24, display: "flex", justifyContent: "center" }}><Logo lc={C.text} w={200} /></div>
            <input type="password" placeholder="Senha" defaultValue="demo" style={{ ...sty.input, marginBottom: 16, textAlign: "center" }} />
            <button onClick={() => setStep("select")} style={{ ...sty.btn, width: "100%" }}>Entrar</button>
            <div style={{ fontSize: 11, color: C.mut, marginTop: 12 }}>Use qualquer senha (protótipo)</div>
          </div>
        </div>
      )}

      {/* SELECT */}
      {step === "select" && (
        <div>
          <h2 style={{ fontSize: 24, fontWeight: 400, marginBottom: 24, fontFamily: "'Marisa',serif" }}>Novo relatório</h2>
          <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr" : "1fr 1fr 1fr", gap: 16, marginBottom: 24 }}>
            <div>
              <label style={sty.label}>Marca</label>
              <select value={brandId} onChange={e => setBrandId(e.target.value)} style={sty.select}>
                {brands.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
              </select>
            </div>
            <div>
              <label style={sty.label}>Canal</label>
              <select style={sty.select}><option>Instagram</option><option>TikTok</option><option>YouTube</option></select>
            </div>
            <div>
              <label style={sty.label}>Período</label>
              <input value={periodKey} onChange={e => setPeriodKey(e.target.value)} style={sty.input} />
            </div>
          </div>
          <button onClick={() => setStep("upload")} style={sty.btn}>Continuar</button>

          <div style={{ marginTop: 40 }}>
            <div style={{ fontSize: 12, color: C.mut, letterSpacing: "0.06em", textTransform: "uppercase", marginBottom: 12 }}>Relatórios publicados</div>
            {[{ b: "Monte Dourado", p: "Fev 2026" }, { b: "Monte Dourado", p: "Jan 2026" }].map((r, i) => (
              <div key={i} style={{ ...gl(C), padding: "12px 16px", marginBottom: 6, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div><span style={{ fontSize: 13 }}>{r.b}</span><span style={{ color: C.mut, fontSize: 12, marginLeft: 8 }}>Instagram · {r.p}</span></div>
                <span style={{ fontSize: 10, color: C.up, letterSpacing: "0.1em", textTransform: "uppercase" }}>Publicado</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* UPLOAD */}
      {step === "upload" && (
        <div>
          <button onClick={() => setStep("select")} style={{ ...sty.btnOut, padding: "8px 14px", fontSize: 10, marginBottom: 20 }}>&#9664; Voltar</button>
          <h2 style={{ fontSize: 24, fontWeight: 400, marginBottom: 8, fontFamily: "'Marisa',serif" }}>{brands.find(b => b.id === brandId)?.name} · {periodKey}</h2>
          <p style={{ color: C.sec, fontSize: 14, marginBottom: 24 }}>Envie o PDF e/ou DOCX. A IA extrai os dados automaticamente.</p>

          <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr" : "1fr 1fr", gap: 16, marginBottom: 24 }}>
            <label style={{ ...gls(C), padding: 24, textAlign: "center", cursor: "pointer", display: "block" }}>
              <div style={{ fontSize: 10, color: C.douDim, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12 }}>PDF do relatório</div>
              <input type="file" accept=".pdf" style={{ display: "none" }} onChange={e => setPdfName(e.target.files[0]?.name || "")} />
              <div style={{ ...gl(C), padding: "12px 20px", display: "inline-block", fontSize: 12, color: C.sec, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer" }}>Escolher arquivo</div>
              {pdfName && <div style={{ fontSize: 12, color: C.up, marginTop: 10 }}>{pdfName}</div>}
            </label>
            <label style={{ ...gls(C), padding: 24, textAlign: "center", cursor: "pointer", display: "block" }}>
              <div style={{ fontSize: 10, color: C.douDim, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 12 }}>DOCX do relatório</div>
              <input type="file" accept=".docx" style={{ display: "none" }} onChange={e => setDocxName(e.target.files[0]?.name || "")} />
              <div style={{ ...gl(C), padding: "12px 20px", display: "inline-block", fontSize: 12, color: C.sec, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer" }}>Escolher arquivo</div>
              {docxName && <div style={{ fontSize: 12, color: C.up, marginTop: 10 }}>{docxName}</div>}
            </label>
          </div>

          <button onClick={simulateExtraction} style={sty.btn}>Extrair dados com IA</button>
        </div>
      )}

      {/* EXTRACTING */}
      {step === "extracting" && (
        <div style={{ textAlign: "center", padding: "60px 20px" }}>
          <div style={{ width: 60, height: 60, borderRadius: "50%", border: `2px solid ${C.border}`, borderTopColor: C.dourado, margin: "0 auto 20px", animation: "spin 1s linear infinite" }} />
          <div style={{ fontSize: 16, marginBottom: 8 }}>Extraindo dados...</div>
          <div style={{ width: "100%", maxWidth: 300, height: 4, background: C.border, borderRadius: 2, margin: "16px auto 0", overflow: "hidden" }}>
            <div style={{ height: "100%", background: C.dourado, borderRadius: 2, width: `${progress}%`, transition: "width 0.3s" }} />
          </div>
          <div style={{ fontSize: 12, color: C.mut, marginTop: 8 }}>{progress}%</div>
          <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
        </div>
      )}

      {/* REVIEW */}
      {step === "review" && editData && (
        <div>
          <button onClick={() => setStep("upload")} style={{ ...sty.btnOut, padding: "8px 14px", fontSize: 10, marginBottom: 20 }}>&#9664; Reenviar</button>
          <h2 style={{ fontSize: 24, fontWeight: 400, marginBottom: 8, fontFamily: "'Marisa',serif" }}>Revisar dados extraídos</h2>
          <p style={{ color: C.sec, fontSize: 14, marginBottom: 24 }}>Confira e edite os valores antes de publicar.</p>

          <div style={{ ...gls(C), padding: 20, marginBottom: 16 }}>
            <div style={sty.label}>KPIs extraídos pela IA</div>
            <div style={{ display: "grid", gridTemplateColumns: mob ? "1fr" : "1fr 1fr", gap: 12 }}>
              {Object.entries(editData).map(([key, val]) => (
                <div key={key} style={{ background: C.bg, borderRadius: 8, padding: "12px 14px" }}>
                  <div style={{ fontSize: 10, color: C.mut, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 6 }}>{key.replace(/_/g, " ")}</div>
                  <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
                    <div>
                      <span style={{ fontSize: 10, color: C.mut }}>Atual</span>
                      <input value={val.v?.toLocaleString("pt-BR")} readOnly style={{ ...sty.input, width: 110, padding: "8px 10px", fontSize: 16, fontWeight: 500, marginTop: 2 }} />
                    </div>
                    <div>
                      <span style={{ fontSize: 10, color: C.mut }}>Anterior</span>
                      <input value={val.prev?.toLocaleString("pt-BR") || "—"} readOnly style={{ ...sty.input, width: 100, padding: "8px 10px", fontSize: 13, marginTop: 2 }} />
                    </div>
                    {val.pct != null && <div style={{ fontSize: 12, color: val.pct > 0 ? C.up : C.down, fontWeight: 500, alignSelf: "flex-end", paddingBottom: 10 }}>{val.pct > 0 ? "\u25B2 +" : "\u25BC "}{val.pct}%</div>}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div style={{ ...gl(C), padding: 20, marginBottom: 24, background: C.dourado + "08" }}>
            <div style={sty.label}>Leitura gerada pela IA</div>
            <div style={{ fontSize: 16, fontWeight: 400, marginBottom: 8 }}>Março consolidou conteúdo como motor de crescimento.</div>
            <p style={{ fontSize: 13, color: C.sec, lineHeight: 1.6 }}>Interações explodiram +387% com os campeonatos QS e Surf na Laje. Alcance orgânico cresceu 50%, ultrapassando 11 mil. Carrosséis atingiram 9,74% de engajamento.</p>
          </div>

          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            <button onClick={simulatePublish} style={sty.btn}>Publicar no painel</button>
            <button onClick={() => setStep("upload")} style={sty.btnOut}>Reenviar arquivos</button>
          </div>
        </div>
      )}

      {/* DONE */}
      {step === "done" && (
        <div style={{ textAlign: "center", padding: "60px 20px" }}>
          <div style={{ width: 60, height: 60, borderRadius: "50%", background: C.up + "22", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 20px", fontSize: 28, color: C.up }}>&#10003;</div>
          <div style={{ fontSize: 22, fontWeight: 400, marginBottom: 8, fontFamily: "'Marisa',serif" }}>Publicado</div>
          <p style={{ fontSize: 14, color: C.sec, marginBottom: 24 }}>O painel dos sócios já está atualizado com os novos dados.</p>
          <div style={{ display: "flex", gap: 12, justifyContent: "center", flexWrap: "wrap" }}>
            <button onClick={onSwitch} style={sty.btn}>Ver painel do sócio</button>
            <button onClick={() => { setStep("select"); setPdfName(""); setDocxName(""); }} style={sty.btnOut}>Novo relatório</button>
          </div>
        </div>
      )}
    </main>

    {/* FOOTER */}
    <footer style={{ borderTop: `1px solid ${C.glassBd}`, padding: mob ? "28px 14px" : "36px 28px", marginTop: mob ? 24 : 40 }}>
      <div style={{ maxWidth: 720, margin: "0 auto", textAlign: "center" }}>
        <Logo lc={C.mut} w={mob ? 100 : 120} />
        <div style={{ fontSize: 8, color: C.douDim, fontFamily: "'Gotham',sans-serif", marginTop: 10, letterSpacing: "0.03em" }}>Powered by <span style={{ color: C.dourado }}>Vitória Rocha</span> adaptado para <span style={{ color: C.dourado }}>Monte Dourado</span>.</div>
      </div>
    </footer>
  </div>;
}

/* ============================================================
   APP PRINCIPAL (alterna entre visões)
============================================================ */
export default function App() {
  const [view, setView] = useState("socio");
  const [mode, setMode] = useState("dark");
  const C = themes[mode];
  const toggle = () => setMode(mode === "dark" ? "light" : "dark");
  return view === "socio"
    ? <SocioView onSwitch={() => setView("admin")} C={C} mode={mode} toggle={toggle} />
    : <AdminView onSwitch={() => setView("socio")} C={C} mode={mode} toggle={toggle} />;
}
